import React, { useEffect, useState } from 'react'
import Popup from '../Popup/popup'
import { getClientUrlDataToken, getMasterDataToken } from '../../../Utils/restUtils'
import { getmessageChannel, getmessageChannelEnable, getmessageChannelEnableRole, messageBalace } from '../../../CommonUrl'
import { useSelector } from 'react-redux'
import { useNavigate } from 'react-router'

function LowMessageCreditAlert({isOpen}) {
    const [balanceData, setBalanceData] = useState(null)
    const [modal, setModal] = useState(false)
    const [isEnabled, setIsEnabled] = useState()

    const today = new Date().toISOString().split("T")[0];
    const recurringAlert = localStorage.getItem("recurringAlert");
    const invoiceAlert = localStorage.getItem("invoiceAlert");



    const authState = useSelector((state) => state.auth);
    const navigate = useNavigate()
    ///modal open
    const handleModal = () => {
        setModal(!modal)
    }
    useEffect(() => {
        handleGetCreditDetails()

    }, [])

    useEffect(() => {
        if (balanceData) {
            getNotificationCannel()
        }
    }, [balanceData])

    //message is enabled
    const getNotificationCannel = async () => {
        let data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getmessageChannelEnable : getmessageChannelEnableRole)
        if (data?.status === true) {
            setIsEnabled(false)
            if (data?.data === true && Number(balanceData?.balance) < 100) {
                if (isOpen === 'invoice') {
                    if (today !== invoiceAlert) {
                        setModal(true)
                        localStorage.setItem("invoiceAlert", today);


                    }

                }
                else if (isOpen === 'recurring') {
                    if (today !== recurringAlert) {
                        setModal(true)
                        localStorage.setItem("recurringAlert", today);

                    }
                }
            }
        }
        else if (data?.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data?.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }

    }

    //set message credit balance
    const handleGetCreditDetails = async () => {
        let data = await getMasterDataToken(messageBalace + `?user_id=${authState?.userId}`);
        if (data?.status === true) {
            setBalanceData(data?.data)
        }

    }
    const navigateToAddCredit = () => {
        navigate('/settings/message-credit')
    }
    return (
        <Popup isOpen={modal} toggler={handleModal} title='Warning' size="md">
            <p style={{ fontSize: '16px', fontWeight: 'bold' }}>Low Message Credit</p>
            <span>You don’t have enough message credits to send SMS or WhatsApp notifications </span>
            <span>You can continue without notifications or add credits to enable messaging.</span>
            <div className='d-flex justify-content-end gap-2 mt-4'>
                <button className='btn btn-secondary' onClick={handleModal}>Continue Without Notifications</button>
                <button className='btn btn-primary' onClick={navigateToAddCredit}>Add Credits</button>
            </div>
        </Popup>
    )
}

export default LowMessageCreditAlert