import React, { Fragment, useState, useEffect, useRef } from 'react';
import { Card, CardHeader, CardBody, Dropdown, DropdownToggle, DropdownMenu, DropdownItem, Form, Row, Col } from 'reactstrap';
import DataTable from 'react-data-table-component';
import { H3, Btn, Breadcrumbs, H4 } from '../../../AbstractElements';
import { Link, useNavigate } from 'react-router-dom';
import { getClientUrlDataToken, postClientUrlWithToken } from '../../../Utils/restUtils';
import { AddOrder, AddSub, Invoice, InvoiceList, Search, orderStatus, Filter, Customer, Export, paymentStatus, CasProvider } from '../../../Constant';
import { viewInvoiceTable, viewInvoiceTableRole, getCustomers, getCustomersRole, deleteInvoice, deleteInvoiceRole, getProvider, getProviderRole } from '../../../CommonUrl';
import { useSelector } from 'react-redux';
import DatePicker from 'react-datepicker';
import { conditionalRow } from '../../Common/Rowstyle/Rowstyle';
import moment from 'moment';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import 'jspdf-autotable';
import { toast } from 'react-toastify';
import SweetAlert from 'sweetalert2';
import Transparentspinner from '../../Common/Loader/Transparentspinner';
import Typeahead from '../../../CommonElements/TypeAhead';
import LowMessageCreditAlert from '../../Common/messageCreditAlert/LowMessageCreditAlert';

const InvoiceContainer = () => {
    const [spinnerTrans, setspinnerTrans] = useState(false);
    const navigate = useNavigate();
    const authState = useSelector((state) => state.auth);
    const toggleStyle = { padding: '10px 20px', opacity: '0.8', fontSize: '14px' };
    const [invoiceLists, setInvoiceList] = useState([]);
    const [filters, setFilters] = useState({
        search: '',
        start: '',
        end: '',
        customer: '',
        orderStatus: '',
        paymentStatus: '',
        providerId: ''
    });
    const [resetPaginationToggle, setResetPaginationToggle] = useState(false);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [currentPage, setCurrentPage] = useState(1);
    const [apiCustomer, setapiCustomer] = useState([]);
    const [customerOptions, setCustomerOptions] = useState([]);
    const [dateRange, setDateRange] = useState([null, null]);
    const [startDate, endDate] = dateRange;
    const [isCustomer, setIsCustomer] = useState(filters.customer);
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const [sortConfig, setSortConfig] = useState({ column: '', order: '' });
    const [provider, setProvider] = useState([]);


    const isSearched = useRef(null);
    const isOrderstatus = useRef(null);
    const isPaymentstatus = useRef(null);
    const isCasProvider = useRef(null);

    const orderStatusOptions = [
        { value: "pending", label: "Pending" },
        { value: "processed", label: "Processed" }
    ];
    const payStatusOptions = [
        { value: "pending", label: "Pending" },
        { value: "partially_paid", label: "Partially Paid" },
        { value: "paid", label: "Paid" }

    ];

    useEffect(() => {
        fetchInvoice(1);
        customerData();
        providerData()
    }, []);

    useEffect(() => {
        const customerOptions = apiCustomer.map((customer) => ({
            value: customer.id,
            label: customer.name,
        }));
        setCustomerOptions(customerOptions);
    }, [apiCustomer]);

    const invoiceColumns = [
        {
            name: <H4>Sl.No</H4>,
            selector: row => row.Si,
            width: '70px',
            center: true,

        },
        {
            name: <i className="fa fa-gears" style={{ fontSize: '15px' }}></i>,
            selector: row => row.action,
            cell: row => <ActionCell row={row} />,
            center: true,
            width: '55px'
        },
        {
            name: <H4>Invoice No</H4>,
            id: 'invoice_no',
            selector: row =>
                <Link style={{ textDecoration: 'underline' }} to={`${process.env.PUBLIC_URL}/customers/customer/userProfile/invoice?invoice_id=${row.id}&customer_id=${row.customer_id}`}>
                    {row.InvoiceNo}
                </Link>,
            sortable: true,
            wrap: true,
            minWidth: '140px'
        },
        {
            name: <H4>Subscriber Id</H4>,
            id: 'subscriber_id',
            selector: row =>
                (authState.userRole === 1 || authState.permissions.includes('show-customer-profile')) ?
                    <Link style={{ textDecoration: 'underline' }} to={`${process.env.PUBLIC_URL}/customers/customer/userProfile?id=${row.customer_id}`}>
                        {row.Sub}
                    </Link> : row.Sub,
            sortable: true,
            wrap: true,
            width: '120px',
        },
        {
            name: <H4>Customer</H4>,
            id: 'name',
            selector: row => row.Customer,
            sortable: true,
            minWidth: '160px',
            wrap: true
        },
        {
            name: <H4>Type</H4>,
            id: 'connection_type',
            selector: row => row.con_type,
            sortable: true,
            minWidth: '105px'
        },

        {
            name: <H4>CAS/ISP Provider</H4>,
            id: 'provider_name',
            selector: row => row.provider,
            sortable: true,
            minWidth: '135px'
        },
        {
            name: <H4>Amount</H4>,
            id: 'amount',
            selector: row => `${authState.currency} ${row.Amount}`,
            sortable: true,
            minWidth: '105px',

        },
        {
            name: <H4>Balance</H4>,
            id: 'balance',
            selector: row => <span className='text-danger' style={{ fontWeight: 'bold' }}>{authState.currency} {row.balance}</span>,
            sortable: true,
            minWidth: '105px',
        },
        {
            name: <H4>Payment Status</H4>,
            selector: row => (<span
                className={`badge badge-${row.payment_status}`} >

                {row.payment_status}

            </span>
            ),
            minWidth: '140px'
        },
        {
            name: <H4>Invoice Date</H4>,
            id: 'invoice_date',
            selector: row => row.InvoiceDate,
            sortable: true,
            minWidth: '165px'
        },
        {
            name: <H4>Created By</H4>,
            id: 'created_by',
            selector: row => row.CreatedBy,
            sortable: true,
            minWidth: '165px'
        },
        {
            name: <H4>Due Date</H4>,
            id: 'created_by',
            selector: row => row.dueDate,
            sortable: true,
            minWidth: '165px'
        },
        {
            name: <H4>Comments</H4>,
            id: 'comments',
            selector: row => row.Comments,
            sortable: true,
            minWidth: '165px'
        },
        {
            name: <H4>Order Status</H4>,
            selector: row => (<span
                className={`badge badge-${row.order_status}`} >
                {row.order_status}
            </span>
            ),
            minWidth: '140px'
        },
    ];

    const handleSort = (column) => {
        let newOrder = 'asc';
        if (sortConfig.column === column.id) {
            newOrder = sortConfig.order === 'asc' ? 'desc' : 'asc';
        }
        setSortConfig({ column: column.id, order: newOrder });
        fetchInvoice(currentPage, perPage, filters.search, filters.start, filters.end, isCustomer?.value, filters.orderStatus, filters.paymentStatus, column.id, newOrder);
    };

    const handleApiError = (status) => {
        if (status >= 400 && status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (status >= 500 && status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
    };

    const handleChange = (selectedOption) => {
        setIsCustomer(selectedOption);
    };

    const toggleDropdown = () => setDropdownOpen(!dropdownOpen);

    const customerData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getCustomers : getCustomersRole);
        if (data.status === true) {
            setapiCustomer(data.data);
        } else {
            handleApiError(data.status);
        }
    };

    const handlePaymentClick = (id, cust_id) => {
        const payFormURL = `${process.env.PUBLIC_URL}/customers/customer/userProfile/invoice?invoice_id=${id}&customer_id=${cust_id}`;
        navigate(payFormURL);

    }

    const handleEditClick = (id) => {
        const editURL = `${process.env.PUBLIC_URL}/billing/order-edit?order_id=${id}`;
        navigate(editURL);
    }

    const providerData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getProvider : getProviderRole);
        if (data.status === true) {
            setProvider(data.data);
        } else {
            handleApiError(response.status)
        }
    };

    const ActionCell = ({ row }) => {
        const [dropdownOpen, setDropdownOpen] = React.useState(false);
        const toggleDropdown = () => setDropdownOpen(!dropdownOpen);

        const deleteInvoices = () => {
            SweetAlert.fire({
                title: 'Confirm deletion?',
                text: 'This action cannot be undone.',
                icon: 'warning',
                showCancelButton: true,
                confirmButtonText: 'Ok',
                cancelButtonText: 'cancel',
                reverseButtons: true
            }).then(async (result) => {
                setLoading(true)
                if (result.value) {
                    const deleteRes = { order_id: row.id }
                    const invoiceDelete = await postClientUrlWithToken(authState.apiUrl, authState.userRole === 1 ? deleteInvoice : deleteInvoiceRole, deleteRes);
                    if (invoiceDelete.status == 200) {
                        if (invoiceDelete.data.status == true) {
                            SweetAlert.fire(
                                'Deleted!',
                                'Your file has been deleted.',
                                'success'
                            );
                            fetchInvoice(currentPage, perPage, filters.search, filters.start, filters.end, filters.customer, filters.orderStatus, filters.paymentStatus, sortConfig.column, sortConfig.order);
                        } else {
                            toast.error(invoiceDelete.data.message);
                            setLoading(false)
                        }
                    } else {
                        handleApiError(invoiceDelete.status);
                    }
                }
                setLoading(false)
            })
        }

        return (
            <Dropdown isOpen={dropdownOpen} toggle={toggleDropdown}>
                <DropdownToggle color="#00000" style={{ fontSize: '14px', zIndex: 1000 }}>
                    <i className="fa fa-ellipsis-v"></i>
                </DropdownToggle>
                <DropdownMenu container="body">
                    <DropdownItem style={toggleStyle} onClick={() => handlePaymentClick(row.id, row.customer_id)}>Invoice</DropdownItem>
                    {
                    (row.payment_status === "pending" && row.type === "sale_order" ) &&
                        <DropdownItem style={toggleStyle} onClick={() => handleEditClick(row.id)}>Edit</DropdownItem>
                    }
                    {row.payment_status === "pending" && (authState.userRole === 1 || authState.permissions.includes('delete-invoice')) &&
                        <DropdownItem style={{ padding: '10px 20px', color: 'red', opacity: '0.8', fontSize: '14px', margin: '0' }} onClick={() => deleteInvoices()}>Delete</DropdownItem>
                    }
                </DropdownMenu>
            </Dropdown>
        );
    };

    const fetchInvoice = async (page, size = perPage, searchKey = "", start_date = '', end_date = '', customer_id = '', orderStatus = '', payment_status = '', providerId = '', sortBy = '', sortOrder = '') => {
        setspinnerTrans(true)
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? viewInvoiceTable +
            `?page=${page}&page_length=${size}&search=${searchKey}&customer_id=${customer_id}
            &start_date=${start_date}&end_date=${end_date}&status=${orderStatus}&payment_status=${payment_status}
            &sort_by=${sortBy}&sort_order=${sortOrder}&provider_id=${providerId}` : viewInvoiceTableRole + `?page=${page}&page_length=${size}
            &search=${searchKey}&customer_id=${customer_id}&start_date=${start_date}&end_date=${end_date}
            &status=${orderStatus}&payment_status=${payment_status}&sort_by=${sortBy}&sort_order=${sortOrder}&provider_id=${providerId}`);
        if (response.status === true) {
            setResetPaginationToggle(!resetPaginationToggle);
            const SerialNo = (page - 1) * size + 1;
            setInvoiceList(response.data.data.map((e, index) => {
                return {
                    Si: SerialNo + index,
                    Sub: <span>{e.subscriber_id}</span>,
                    Customer: e.customer_name || 'N/A',
                    Amount: e.amount || 'N/A',
                    balance: e.balance || 'N/A',
                    InvoiceDate: e.invoice_date || 'N/A',
                    InvoiceNo: e.invoice_number || 'N/A',
                    Status: e.status || 'N/A',
                    order_status: e.order_status || 'N/A',
                    id: e.id || 'N/A',
                    customer_id: e.customer_id || 'N/A',
                    con_type: e.connection_type || 'N/A',
                    payment_status: e.payment_status || 'N/A',
                    dueDate: e.due_date || 'N/A',
                    CreatedBy: e.created_by || 'N/A',
                    Comments: e.comments || 'N/A',
                    provider: e.provider_name || 'N/A',
                    type: e.type || 'N/A'

                }
            }))
            setTotalRows(response.data.total);
        } else {
            handleApiError(response.status);
        }
        setspinnerTrans(false)
    };
    const exportInvoiceExcel = async () => {
        setspinnerTrans(true)
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ?
            viewInvoiceTable + `?export=wallet_data&search=${filters?.search ? filters.search : ''}
            &start_date=${filters?.start ? filters.start : ''}&end_date=${filters?.end ? filters.end : ''}
            &customer_id=${filters?.customer ? filters.customer : ''}
            &status=${filters?.orderStatus ? filters.orderStatus : ''}&paymentStatus=${filters?.paymentStatus ? filters.paymentStatus : ''}
            &sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`
            : viewInvoiceTableRole + `?export=wallet_data&search=${filters?.search ? filters.search : ''}
            &start_date=${filters?.start ? filters.start : ''}&end_date=${filters?.end ? filters.end : ''}
            &customer_id=${filters?.customer ? filters.customer : ''}
            &status=${filters?.orderStatus ? filters.orderStatus : ''}&paymentStatus=${filters?.paymentStatus ? filters.paymentStatus : ''}
            &sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`);
        const dataToExport = response.data.map(({ invoice_number, subscriber_id, customer_name, connection_type, amount, balance, payment_status, invoice_date, order_status }) => ({ Invoice_No: invoice_number, Subscriber_Id: subscriber_id, Customer: customer_name, Type: connection_type, Amount: amount, Balance: balance, payment_status, Invoice_Date: invoice_date, Order_Status: order_status }));
        if (response.status === true) {
            const ws = XLSX.utils.json_to_sheet(dataToExport);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, 'Invoice Data');
            XLSX.writeFile(wb, 'Invoice_data.xlsx');
        } else {
            handleApiError(response.status);
        }
        setspinnerTrans(false)
    };

    const exportInvoicePdf = async () => {
        setspinnerTrans(true)
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ?
            viewInvoiceTable + `?export=wallet_data&search=${filters?.search ? filters.search : ''}
            &start_date=${filters?.start ? filters.start : ''}&end_date=${filters?.end ? filters.end : ''}
            &customer_id=${filters?.customer ? filters.customer : ''}
            &status=${filters?.orderStatus ? filters.orderStatus : ''}&paymentStatus=${filters?.paymentStatus ? filters.paymentStatus : ''}
            &sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`
            : viewInvoiceTableRole + `?export=wallet_data&search=${filters?.search ? filters.search : ''}
            &start_date=${filters?.start ? filters.start : ''}&end_date=${filters?.end ? filters.end : ''}
            &customer_id=${filters?.customer ? filters.customer : ''}
            &status=${filters?.orderStatus ? filters.orderStatus : ''}&paymentStatus=${filters?.paymentStatus ? filters.paymentStatus : ''}
            &sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`);
        const dataToExport = response.data.map(({ invoice_number, subscriber_id, customer_name, connection_type, amount, balance, payment_status, invoice_date, order_status }, index) => ({ Sl: index + 1, invoice_number, subscriber_id, customer_name, connection_type, amount, balance, payment_status, invoice_date, order_status }));
        if (response.status === true) {
            const doc = new jsPDF();
            const columns = ["Sl", "Invoice No", "Subscriber Id", "Customer", "Type", "Amount", "Balance", "Payment Status", "Invoice Date", "Order Status"];
            const rows = dataToExport.map(({ invoice_number, subscriber_id, customer_name, connection_type, amount, balance, payment_status, invoice_date, order_status }, index) => [index + 1, invoice_number, subscriber_id, customer_name, connection_type, amount, balance, payment_status, invoice_date, order_status]);
            doc.autoTable({
                head: [columns],
                body: rows
            });
            doc.save("invoice_data.pdf");
        } else {
            handleApiError(response.status);
        }
        setspinnerTrans(false)
    };

    const handlePageChange = page => {
        fetchInvoice(page, perPage, filters.search, filters.start, filters.end, filters.customer, filters.orderStatus, filters.paymentStatus, sortConfig.column, sortConfig.order);
        setCurrentPage(page);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        fetchInvoice(page, newPerPage, filters.search, filters.start, filters.end, filters.customer, filters.orderStatus, filters.paymentStatus, sortConfig.column, sortConfig.order);
        setPerPage(newPerPage);
    };

    const handleFilter = async (e) => {
        e.preventDefault();
        const search = isSearched.current.value;
        const customerId = isCustomer?.value;
        const orderStatus = isOrderstatus.current.value;
        const paymentStatus = isPaymentstatus.current.value;
        const providerId = isCasProvider.current.value;
        const start = startDate ? moment(startDate).format("DD-MM-YYYY") : '';
        const end = endDate ? moment(endDate).format("DD-MM-YYYY") : '';
        setFilters({
            search,
            start,
            end,
            customerId,
            orderStatus,
            paymentStatus,
            providerId
        });
        fetchInvoice(1, perPage, search, start, end, customerId, orderStatus, paymentStatus, providerId);
    };


    return (
        <Fragment>
            {spinnerTrans && <Transparentspinner />}
            <Breadcrumbs mainTitle={Invoice} parent="Billing" title={Invoice} />
            <Card className='cardWidth'>
                <CardHeader style={{ margin: '-25px 0 -35px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <H3>{InvoiceList}</H3>
                    <div>
                        <CardBody className="dropdown-basic" style={{ borderRadius: '5px' }}>
                            <Link to={`${process.env.PUBLIC_URL}/billing/order-add`} className="btn btn-primary me-md-2 button-addsale">{AddOrder}</Link>
                            <Link to={`${process.env.PUBLIC_URL}/billing/subscription-add`} className="btn btn-primary me-md-2 button-addsale" >{AddSub}</Link>
                            <Dropdown isOpen={dropdownOpen} toggle={toggleDropdown}>
                                <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4 button-addsale">
                                    {Export} <i className="icofont icofont-arrow-up"></i>
                                </DropdownToggle>
                                <DropdownMenu container="body">
                                    <DropdownItem style={toggleStyle} onClick={() => exportInvoiceExcel()}><i className="fa fa-file-excel-o me-2"></i> Excel</DropdownItem>
                                    <DropdownItem style={toggleStyle} onClick={() => exportInvoicePdf()}><i className="fa fa-file-pdf-o me-2"></i> Pdf</DropdownItem>
                                </DropdownMenu>
                            </Dropdown>
                        </CardBody>
                    </div>

                </CardHeader>
                <CardBody>
                    <span className=''>
                        <Form className="needs-validation" noValidate onSubmit={handleFilter}>

                            <Row className="ps-3 gap-sm-3 gap-md-2 mb-4 filterGap">
                                <Col sm="12" md='5' lg='2'>
                                    <input name='search' className="form-control" placeholder={Search} id="validationCustom01" type="text" ref={isSearched}
                                    />
                                </Col>
                                <Col sm="12" md="5" lg='2' className="form-element">
                                    <div style={{ position: 'relative', zIndex: 2 }}>
                                        <DatePicker
                                            className="form-control digits w-100"
                                            selectsRange={true}
                                            startDate={startDate}
                                            endDate={endDate}
                                            onChange={(update) => {
                                                setDateRange(update);
                                            }}
                                            isClearable={true}
                                            monthsShown={2}
                                            popperPlacement="bottom"
                                            calendarClassName='parallel-calendar'
                                            placeholderText='Select Date Range'
                                            dateFormat="dd/MM/yyyy"
                                        />
                                    </div>
                                </Col>
                                <Col sm="12" md="5" lg="3" className="form-element">
                                    <Typeahead
                                        options={customerOptions}
                                        onChange={handleChange}
                                        placeholder="Customer..."
                                        isClearable
                                    />
                                </Col>
                                <Col sm="12" md="5" lg='2' className="form-element">
                                    <select className="form-select" ref={isOrderstatus}>
                                        <option value="">{orderStatus}</option>
                                        {orderStatusOptions.map((option, index) => (
                                            <option key={index} value={option.value}>{option.label}</option>
                                        ))}
                                    </select>
                                </Col>
                                <Col sm="12" md="5" lg='2' className="form-element">
                                    <select className="form-select" ref={isPaymentstatus}>
                                        <option value="">{paymentStatus}</option>
                                        {payStatusOptions.map((option, index) => (
                                            <option key={index} value={option.value}>{option.label}</option>
                                        ))}
                                    </select>
                                </Col>
                                <Col sm="12" md="5" lg='2' className="form-element">
                                    <select className="form-select" name='provider' ref={isCasProvider}>
                                        <option value="">{CasProvider}</option>
                                        {provider.map((values, index) => (
                                            <option key={index} value={values.id}>{values.name}</option>
                                        ))}
                                    </select>
                                </Col>
                                <Col sm="12" md="5" lg='1' className="custom-filtrs">
                                    <Btn attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                                </Col>
                            </Row>
                        </Form>
                    </span>
                    <div className="order-history table-responsive">
                        <DataTable
                            columns={invoiceColumns}
                            data={invoiceLists}
                            progressPending={loading}
                            onSort={handleSort} // Attach sorting handler here
                            sortServer // Enable server-side sorting
                            pagination
                            paginationServer
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            paginationTotalRows={totalRows}
                            paginationDefaultPage={currentPage}
                            onChangeRowsPerPage={handlePerRowsChange}
                            conditionalRowStyles={conditionalRow}
                            onChangePage={handlePageChange}
                            fixedHeader
                        />
                    </div>
                </CardBody>
                <LowMessageCreditAlert isOpen={'invoice'} />
            </Card>
        </Fragment >
    );
};

export default InvoiceContainer;
